function searchFilter(e,t){var l,r,n,a;for(l=document.getElementById(e).value.toUpperCase(),r=document.getElementById(t).getElementsByTagName("tr"),a=0;a<r.length;a++)(n=r[a].getElementsByTagName("td")[0])&&(n.innerHTML.toUpperCase().indexOf(l)>-1?r[a].style.display="":r[a].style.display="none")}document.querySelectorAll(".close-filter").forEach(e=>{e.addEventListener("click",e=>{e.preventDefault(),document.querySelector(".search__filter-properties").classList.toggle("active")})}),document.querySelector("#searchClient").addEventListener("keyup",()=>{searchFilter("searchClient","tableClient")});